1	const PROCESSING_FEE = 5;
2	const DEFAULT_BASE_PREMIUM = 100;
3	
4	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
5	type Step = { op: string; items: QuoteItem[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  amulet: 60,
10	  rune: 25,
11	};
12	
13	const basePremiumForItem = (item: QuoteItem): number =>
14	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
15	
16	const sumBasePremiums = (items: QuoteItem[]): number =>
17	  items.reduce((total, item) => total + basePremiumForItem(item), 0);
18	
19	const quoteStep = (step: Step) => ({
20	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
21	});
22	
23	export const runScenario = (scenario: unknown): unknown => {
24	  const { steps } = scenario as Scenario;
25	  return { results: steps.map(quoteStep) };
26	};
