20	        },
21	      ],
22	    });
23	    expect(result.results).toEqual([{ premium: 105 }]);
24	  });
25	  it("quote for a single plain amulet yields 65 G (60 base + 5 fee)", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [
29	        {
30	          op: "quote",
31	          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
32	        },
33	      ],
34	    });
