37	  it("quote for sword + amulet yields 165 G (100 + 60 + 5)", () => {
38	    const result = runScenario({
39	      customer: { yearsWithMHPCO: 0 },
40	      steps: [
41	        {
42	          op: "quote",
43	          items: [
44	            { type: "sword", material: "steel", enchantment: 0, cursed: false },
45	            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
46	          ],
47	        },
48	      ],
49	    });
50	    expect(result.results).toEqual([{ premium: 165 }]);
51	  });
52	
53	  // Components
54	  it("quote for 2 runes yields 55 G (50 base + 5 fee)", () => {
55	    const result = runScenario({
56	      customer: { yearsWithMHPCO: 0 },
57	      steps: [
58	        {
59	          op: "quote",
60	          items: [{ type: "rune" }, { type: "rune" }],
61	        },
62	      ],
63	    });
